package main

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"os"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	"github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/credentials"
	"github.com/aws/aws-sdk-go-v2/service/s3"
	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
)

func main() {
	app := pocketbase.New()

	app.OnServe().BindFunc(func(se *core.ServeEvent) error {
		se.Router.GET("/api/s3-presign", func(e *core.RequestEvent) error {
			filename := e.Request.URL.Query().Get("filename")
			if filename == "" {
				e.Response.Header().Set("Content-Type", "application/json")
				e.Response.WriteHeader(http.StatusBadRequest)
				return json.NewEncoder(e.Response).Encode(map[string]any{
					"code":    400,
					"message": "Missing required query parameter: filename",
					"data":    map[string]any{},
				})
			}

			region := os.Getenv("AWS_REGION")
			accessKeyID := os.Getenv("AWS_ACCESS_KEY_ID")
			secretAccessKey := os.Getenv("AWS_SECRET_ACCESS_KEY")
			bucket := os.Getenv("AWS_BUCKET")
			runID := os.Getenv("ZEALT_RUN_ID")

			if region == "" || accessKeyID == "" || secretAccessKey == "" || bucket == "" {
				e.Response.Header().Set("Content-Type", "application/json")
				e.Response.WriteHeader(http.StatusInternalServerError)
				return json.NewEncoder(e.Response).Encode(map[string]any{
					"code":    500,
					"message": "Missing required S3 configuration environment variables (AWS_REGION, AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY, AWS_BUCKET)",
					"data":    map[string]any{},
				})
			}

			if runID == "" {
				e.Response.Header().Set("Content-Type", "application/json")
				e.Response.WriteHeader(http.StatusInternalServerError)
				return json.NewEncoder(e.Response).Encode(map[string]any{
					"code":    500,
					"message": "Missing required environment variable: ZEALT_RUN_ID",
					"data":    map[string]any{},
				})
			}

			key := fmt.Sprintf("uploads/%s/%s", runID, filename)

			cfg, err := config.LoadDefaultConfig(context.Background(),
				config.WithRegion(region),
				config.WithCredentialsProvider(credentials.NewStaticCredentialsProvider(accessKeyID, secretAccessKey, "")),
			)
			if err != nil {
				e.Response.Header().Set("Content-Type", "application/json")
				e.Response.WriteHeader(http.StatusInternalServerError)
				return json.NewEncoder(e.Response).Encode(map[string]any{
					"code":    500,
					"message": "Failed to configure AWS SDK: " + err.Error(),
					"data":    map[string]any{},
				})
			}

			s3Client := s3.NewFromConfig(cfg)
			presignClient := s3.NewPresignClient(s3Client)

			presignedReq, err := presignClient.PresignPutObject(context.Background(), &s3.PutObjectInput{
				Bucket: aws.String(bucket),
				Key:    aws.String(key),
			}, s3.WithPresignExpires(15*time.Minute))
			if err != nil {
				e.Response.Header().Set("Content-Type", "application/json")
				e.Response.WriteHeader(http.StatusInternalServerError)
				return json.NewEncoder(e.Response).Encode(map[string]any{
					"code":    500,
					"message": "Failed to generate presigned URL: " + err.Error(),
					"data":    map[string]any{},
				})
			}

			e.Response.Header().Set("Content-Type", "application/json")
			return json.NewEncoder(e.Response).Encode(map[string]any{
				"url": presignedReq.URL,
			})
		})

		return se.Next()
	})

	if err := app.Start(); err != nil {
		os.Exit(1)
	}
}
